// Solution
#include <iostream>
#include <vector>

int maxSubarraySum(std::vector<int>& arr) {
	int maxSum = INT_MIN;
	int currentSum = 0;
	for (int i = 0; i < arr.size(); i++) {
		currentSum += arr[i];
		if (currentSum > maxSum) maxSum = currentSum;
		if (currentSum < 0) currentSum = 0;
	}
	return maxSum;
}

int main() {
	std::vector<int> arr = {-2, -3, 4, -1, -2, 1, 5, -3};
	std::cout << maxSubarraySum(arr) << std::endl;
	return 0;
}

